        if (promotionCodes.data.length === 0) {
          return res.status(400).json({ message: "Invalid promo code" });
        }
        stripePromoCodeId = promotionCodes.data[0].id;
      }

      console.log(`[Checkout] Creating session for user ${userId}, plan: ${planId}, cycle: ${billingCycle}, priceId: ${finalPriceId}, promoCode: ${promoCode || 'none'}`);

      // Build checkout session options
      const sessionOptions: any = {
        customer: customerId,
        payment_method_types: ["card"],
        line_items: [{ price: finalPriceId, quantity: 1 }],
        mode: "subscription",
        success_url: `${req.protocol}://${req.get("host")}/billing?success=true`,
        cancel_url: `${req.protocol}://${req.get("host")}/billing?canceled=true`,
        metadata: {
