  app.post("/api/checkout/trial", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { planId = "local", billingCycle = "monthly", promoCode } = req.body;

      // Validate plan allows trial
      const allowedTrialPlans: PlanId[] = ["local", "pro"];
      if (!allowedTrialPlans.includes(planId as PlanId)) {
        return res.status(400).json({ 
          message: "Free trial is only available for Local and Pro plans. Please use the standard checkout for Business or Enterprise plans.",
          code: "TRIAL_NOT_AVAILABLE"
        });
      }

      const validCycles: BillingCycle[] = ["monthly", "yearly"];
      if (!validCycles.includes(billingCycle)) {
        return res.status(400).json({ message: "Invalid billing cycle" });
      }

      const finalPriceId = getStripePriceId(planId as PlanId, billingCycle as BillingCycle);
      if (!finalPriceId) {
        return res.status(400).json({ message: "No price found for this plan and billing cycle" });
      }

      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      // Prevent multiple Pro trials - check if user has already used their Pro trial
      if (planId === "pro" && user.hasUsedProTrial) {
        return res.status(400).json({ 
          message: "You have already used your Pro trial. Please subscribe to continue using Pro features.",
          code: "PRO_TRIAL_ALREADY_USED"
        });
      }

      // Check if user already has an active subscription (prevents trial abuse)
      if (user.stripeSubscriptionId && (user.subscriptionStatus === "active" || user.subscriptionStatus === "trialing")) {
        return res.status(400).json({ 
          message: "You already have an active subscription. Please manage it from your billing page.",
          code: "ALREADY_SUBSCRIBED"
        });
      }

      const stripe = await getUncachableStripeClient();

      // Create or get customer
      let customerId = user.stripeCustomerId;
      if (!customerId) {
        const customer = await stripe.customers.create({
          email: user.email || undefined,
          metadata: { userId },
        });
        await storage.updateUserStripeInfo(userId, { stripeCustomerId: customer.id });
        customerId = customer.id;
      }

      // Validate promo code via Stripe if provided (preserve casing - Stripe is case-sensitive)
      let stripePromoCodeId: string | null = null;
      if (promoCode && typeof promoCode === "string") {
        const promotionCodes = await stripe.promotionCodes.list({
          code: promoCode.trim(),
          active: true,
          limit: 1,
        });
        if (promotionCodes.data.length === 0) {
          return res.status(400).json({ message: "Invalid promo code" });
        }
        stripePromoCodeId = promotionCodes.data[0].id;
      }

      // Calculate trial duration based on plan
      // Local: 3 days, Pro: 3 days
      const trialDays = 3;
      const trialEndTimestamp = Math.floor(Date.now() / 1000) + (trialDays * 24 * 60 * 60);

      // Build checkout session options
      const trialSessionOptions: any = {
        customer: customerId,
        payment_method_types: ["card"],
        line_items: [{ price: finalPriceId, quantity: 1 }],
        mode: "subscription",
        success_url: `${req.protocol}://${req.get("host")}/dashboard?trial_started=true&plan=${planId}`,
        cancel_url: `${req.protocol}://${req.get("host")}/select-plan?canceled=true`,
        metadata: {
          userId,
          planId,
          billingCycle,
          trialCheckout: "true",
          trialDays: trialDays.toString(),
          appliedPromoCode: promoCode || "",
        },
        subscription_data: {
          // Use trial_end for exact control
          trial_end: trialEndTimestamp,
          metadata: {
            userId,
            planId,
            billingCycle,
            trialDays: trialDays.toString(),
            appliedPromoCode: promoCode || "",
          },
        },
        // Always collect payment method upfront
        payment_method_collection: "always",
      };

      // If promo code provided and validated, apply via discounts array
      // Otherwise, allow users to enter promo codes at checkout
      if (stripePromoCodeId) {
        trialSessionOptions.discounts = [{ promotion_code: stripePromoCodeId }];
      } else {
        trialSessionOptions.allow_promotion_codes = true;
      }

      // Create checkout session with trial period
      const session = await stripe.checkout.sessions.create(trialSessionOptions);

      // Mark Pro trial as used when checkout session is created (will be finalized on webhook)
      // This happens BEFORE the user completes checkout to prevent abuse
      if (planId === "pro") {
        await storage.updateUserStripeInfo(userId, { hasUsedProTrial: true });
        console.log(`[Trial] Marked Pro trial as used for user ${userId}`);
      }

      console.log(`[Trial] Created ${trialDays}-day trial checkout for ${planId} plan, user ${userId}`);
      res.json({ url: session.url });
    } catch (error: any) {
      console.error("Error creating trial checkout session:");
      console.error("Error type:", error?.type);
      console.error("Error message:", error?.message);
      console.error("Error code:", error?.code);
      console.error("Full error:", JSON.stringify(error, null, 2));

      res.status(500).json({ message: "Failed to create checkout session", details: error?.message || "Unknown error" });
    }
  });

