import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Switch } from "@/components/ui/switch";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
  Crown,
  CreditCard,
  Loader2,
  ExternalLink,
  XCircle,
  Zap,
  MapPin,
  Building2,
  Globe,
  Reply,
  Sparkles,
  BarChart3,
  Users,
  Palette,
  Headphones,
  LayoutDashboard,
  Shield,
  FileCheck,
  UserCheck,
  User,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { useLocation } from "wouter";
import { PLANS, type PlanId, type BillingCycle } from "@shared/plans";
import { useLanguage } from "@/lib/i18n";

export default function Billing() {
  const { toast } = useToast();
  const { user } = useAuth();
  const [, navigate] = useLocation();
  const { t } = useLanguage();

  const [billingCycle, setBillingCycle] = useState<BillingCycle>("monthly");
  const [showCancelDialog, setShowCancelDialog] = useState(false);

  const {
    data: subscription,
    isLoading,
    refetch,
  } = useQuery({
    queryKey: ["/api/subscription"],
  });

  const checkoutMutation = useMutation({
    mutationFn: async ({
      planId,
      billingCycle,
    }: {
      planId: PlanId;
      billingCycle: BillingCycle;
    }) => {
      const res = await apiRequest("POST", "/api/checkout", {
        planId,
        billingCycle,
      });
      return res.json();
    },
    onSuccess: (data) => {
      if (data.enterprise) navigate("/contact");
      if (data.url) window.location.href = data.url;
    },
  });

  const handleSelectPlan = (planId: PlanId) => {
    if (planId === "enterprise") {
      navigate("/contact");
      return;
    }
    checkoutMutation.mutate({ planId, billingCycle });
  };

  const currentPlan = subscription?.plan || user?.subscriptionPlan;

  const getPrice = (planId: PlanId) => {
    const plan = PLANS[planId];
    if (billingCycle === "yearly") {
      return Math.round(plan.price.yearly / 12);
    }
    return plan.price.monthly;
  };

  const getYearlyTotal = (planId: PlanId) => {
    return PLANS[planId].price.yearly;
  };

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-semibold">{t("billing.title")}</h1>
        <p className="text-muted-foreground">{t("billing.subtitle")}</p>
      </div>

      {/* CURRENT SUBSCRIPTION */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Crown className="h-5 w-5 text-primary" />
            {t("billing.currentSubscription")}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <Skeleton className="h-8 w-40" />
          ) : (
            <div className="flex items-center justify-between flex-wrap gap-4">
              <div className="flex items-center gap-2">
                <span className="font-semibold text-lg">
                  {currentPlan
                    ? PLANS[currentPlan].name
                    : t("billing.status.trial")}
                </span>
                <Badge variant="secondary">{subscription?.status}</Badge>
              </div>
              {subscription?.status === "active" && (
                <Button
                  variant="outline"
                  onClick={() => navigate("/billing/portal")}
                >
                  <CreditCard className="mr-2 h-4 w-4" />
                  {t("billing.manageSubscription")}
                </Button>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* BILLING TOGGLE */}
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">{t("billing.choosePlan")}</h2>
        <div className="flex items-center gap-3">
          <span
            className={
              billingCycle === "monthly"
                ? "font-medium"
                : "text-muted-foreground"
            }
          >
            {t("common.monthly")}
          </span>
          <Switch
            checked={billingCycle === "yearly"}
            onCheckedChange={(v) => setBillingCycle(v ? "yearly" : "monthly")}
          />
          <span
            className={
              billingCycle === "yearly"
                ? "font-medium"
                : "text-muted-foreground"
            }
          >
            {t("common.yearly")}
            <Badge className="ml-2">{t("common.save20")}</Badge>
          </span>
        </div>
      </div>

      {/* PRICING — EXACT COPY FROM LANDING */}
      <div className="grid gap-6 lg:grid-cols-4">
        {/* LOCAL */}
        <PricingCard
          icon={<MapPin />}
          color="emerald"
          plan="local"
          title={t("pricing.local.name")}
          desc={t("pricing.local.description")}
          price={getPrice("local")}
          yearly={getYearlyTotal("local")}
          active={currentPlan === "local"}
          onSelect={() => handleSelectPlan("local")}
          features={[
            t("pricing.local.features.location"),
            t("pricing.local.features.unlimitedNewReplies"),
            t("pricing.local.features.pastReplies"),
            t("pricing.local.features.mode"),
            t("pricing.local.features.analytics"),
            t("pricing.local.features.users"),
            t("pricing.local.features.presets"),
          ]}
          billingCycle={billingCycle}
        />

        {/* PRO */}
        <PricingCard
          popular
          icon={<Zap />}
          color="primary"
          plan="pro"
          title={t("pricing.pro.name")}
          desc={t("pricing.pro.description")}
          price={getPrice("pro")}
          yearly={getYearlyTotal("pro")}
          active={currentPlan === "pro"}
          onSelect={() => handleSelectPlan("pro")}
          features={[
            t("pricing.pro.features.locations"),
            t("pricing.pro.features.unlimitedNewReplies"),
            t("pricing.pro.features.pastReplies"),
            t("pricing.pro.features.analytics"),
            t("pricing.pro.features.priority"),
            t("pricing.pro.features.users"),
            t("pricing.pro.features.presets"),
            t("pricing.pro.features.support"),
          ]}
          billingCycle={billingCycle}
        />

        {/* BUSINESS */}
        <PricingCard
          icon={<Building2 />}
          color="amber"
          plan="business"
          title={t("pricing.business.name")}
          desc={t("pricing.business.description")}
          price={getPrice("business")}
          yearly={getYearlyTotal("business")}
          extra="+€39/location"
          active={currentPlan === "business"}
          onSelect={() => handleSelectPlan("business")}
          features={[
            t("pricing.business.features.locationsIncluded"),
            t("pricing.business.features.extraLocation"),
            t("pricing.business.features.dashboard"),
            t("pricing.business.features.team"),
            t("pricing.business.features.permissions"),
            t("pricing.business.features.sla"),
            t("pricing.business.features.gdpr"),
            t("pricing.business.features.onboarding"),
            t("pricing.business.features.manager"),
          ]}
          billingCycle={billingCycle}
        />

        {/* ENTERPRISE */}
        <PricingCard
          icon={<Globe />}
          color="slate"
          plan="enterprise"
          title={t("pricing.enterprise.name")}
          desc={t("pricing.enterprise.description")}
          custom
          active={false}
          onSelect={() => navigate("/contact")}
          features={[
            t("pricing.enterprise.features.api"),
            t("pricing.enterprise.features.crm"),
            t("pricing.enterprise.features.automations"),
            t("pricing.enterprise.features.auditLogs"),
            t("pricing.enterprise.features.reporting"),
            t("pricing.enterprise.features.sla"),
            t("pricing.enterprise.features.accountManager"),
            t("pricing.enterprise.features.onboarding"),
          ]}
        />
      </div>
    </div>
  );
}

/* ------------------ */
/* PRICING CARD COMP */
/* ------------------ */

function PricingCard({
  icon,
  title,
  desc,
  price,
  yearly,
  features,
  onSelect,
  active,
  popular,
  extra,
  custom,
  billingCycle,
  color, // 👈 AÑADIR
}: any) {
  return (
    <Card
      className={`relative flex flex-col ${popular ? "border-primary shadow-lg" : ""}`}
    >
      {popular && (
        <div className="absolute -top-3 left-1/2 -translate-x-1/2">
          <Badge>Most popular</Badge>
        </div>
      )}

      <CardHeader>
        <div
          className={`
            h-10 w-10 flex items-center justify-center rounded-lg mb-3
            ${
              color === "emerald"
                ? "bg-emerald-100 text-emerald-600 dark:bg-emerald-950 dark:text-emerald-400"
                : color === "primary"
                  ? "bg-primary/10 text-primary"
                  : color === "amber"
                    ? "bg-amber-100 text-amber-600 dark:bg-amber-950 dark:text-amber-400"
                    : "bg-slate-200 text-slate-600 dark:bg-slate-800 dark:text-slate-400"
            }
          `}
        >
          {icon}
        </div>

        <CardTitle>{title}</CardTitle>
        <CardDescription>{desc}</CardDescription>

        <div className="mt-4">
          {custom ? (
            <span className="text-4xl font-bold">Custom</span>
          ) : (
            <>
              <span className="text-4xl font-bold">€{price}</span>
              <span className="text-muted-foreground"> /month</span>
              {billingCycle === "yearly" && (
                <p className="text-xs text-muted-foreground mt-1">
                  €{yearly} billed annually
                </p>
              )}
              {extra && (
                <p className="text-xs text-muted-foreground">{extra}</p>
              )}
            </>
          )}
        </div>
      </CardHeader>

      <CardContent className="flex-1 flex flex-col">
        <ul className="space-y-2 flex-1">
          {features.map((f: string, i: number) => (
            <li key={i} className="flex gap-2 text-sm">
              ✓ {f}
            </li>
          ))}
        </ul>

        <Button
          className="mt-6 w-full"
          variant={active ? "outline" : "default"}
          disabled={active}
          onClick={onSelect}
        >
          {active ? "Current plan" : custom ? "Contact us" : "Start free trial"}
        </Button>
      </CardContent>
    </Card>
  );
}

