                  {t("restaurants.settings.defaultToneDescription")}
                </p>
                <Select
                  value={selectedRestaurant.toneOfVoice || "friendly"}
                  onValueChange={(value) => {
                    updateMutation.mutate({
                      id: selectedRestaurant.id,
