import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ThemeToggle } from "@/components/theme-toggle";
import { LanguageToggle } from "@/components/language-toggle";
import { ArrowLeft } from "lucide-react";
import { Link } from "wouter";
import { useLanguage } from "@/lib/i18n";

export default function Contact() {
  const { t } = useLanguage();
  const [formData, setFormData] = useState({
    name: "",
    companyName: "",
    email: "",
    phone: "",
    message: "",
  });

  const [submitted, setSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      const response = await fetch("/api/contact", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          name: formData.name,
          company: formData.companyName,
          email: formData.email,
          phone: formData.phone || undefined,
          message: formData.message,
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to submit form");
      }

      setSubmitted(true);
      setFormData({
        name: "",
        companyName: "",
        email: "",
        phone: "",
        message: "",
      });
    } catch (err) {
      setError(t("contact.error"));
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-50 border-b bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
        <div className="container mx-auto flex h-16 items-center justify-between px-4">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" asChild>
              <Link href="/">
                <ArrowLeft className="h-5 w-5" />
              </Link>
            </Button>
            <div className="flex items-center py-4">
              <img
                src="/holarevi-dark.png"
                alt="HolaRevi Logo"
                className="h-14 w-auto block dark:hidden object-contain"
              />
              <img
                src="/holarevi-light.png"
                alt="HolaRevi Logo"
                className="h-14 w-auto hidden dark:block object-contain"
              />
            </div>
          </div>
          <div className="flex items-center gap-2">
            <LanguageToggle />
            <ThemeToggle />
          </div>
        </div>
      </header>

      <main className="py-16">
        <div className="container mx-auto px-4">
          <div className="mx-auto max-w-md">
            <Card>
              <CardHeader className="text-center">
                <CardTitle className="text-2xl font-bold">
                  {t("contact.title")}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleSubmit} className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="name">{t("contact.name")}</Label>
                    <Input
                      id="name"
                      name="name"
                      type="text"
                      placeholder={t("contact.namePlaceholder")}
                      value={formData.name}
                      onChange={handleChange}
                      required
                      data-testid="input-name"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="companyName">{t("contact.company")}</Label>
                    <Input
                      id="companyName"
                      name="companyName"
                      type="text"
                      placeholder={t("contact.companyPlaceholder")}
                      value={formData.companyName}
                      onChange={handleChange}
                      required
                      data-testid="input-company-name"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="email">{t("contact.email")}</Label>
                    <Input
                      id="email"
                      name="email"
                      type="email"
                      placeholder={t("contact.emailPlaceholder")}
                      value={formData.email}
                      onChange={handleChange}
                      required
                      data-testid="input-email"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="phone">{t("contact.phone")}</Label>
                    <Input
                      id="phone"
                      name="phone"
                      type="tel"
                      placeholder="+34 600 000 000"
                      value={formData.phone}
                      onChange={handleChange}
                      data-testid="input-phone"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="message">{t("contact.message")}</Label>
                    <Textarea
                      id="message"
                      name="message"
                      placeholder={t("contact.messagePlaceholder")}
                      value={formData.message}
                      onChange={handleChange}
                      required
                      rows={4}
                      data-testid="input-message"
                    />
                  </div>

                  <Button
                    type="submit"
                    className="w-full"
                    disabled={isSubmitting}
                    data-testid="button-submit"
                  >
                    {isSubmitting ? t("contact.sending") : t("contact.submit")}
                  </Button>

                  {error && (
                    <p className="text-destructive text-sm mt-2 text-center" data-testid="text-error">
                      {error}
                    </p>
                  )}

                  {submitted && (
                    <p className="text-green-600 dark:text-green-400 text-sm mt-2 text-center" data-testid="text-success">
                      {t("contact.success")}
                    </p>
                  )}
                </form>
              </CardContent>
            </Card>
          </div>
        </div>
      </main>

      <footer className="border-t py-12">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex flex-wrap justify-center gap-6">
              <Link href="/privacy" className="text-muted-foreground hover:text-foreground transition-colors" data-testid="link-footer-privacy">
                {t("landing.footer.privacy")}
              </Link>
              <Link href="/terms" className="text-muted-foreground hover:text-foreground transition-colors" data-testid="link-footer-terms">
                {t("landing.footer.terms")}
              </Link>
              <Link href="/google-permissions" className="text-muted-foreground hover:text-foreground transition-colors" data-testid="link-footer-google-permissions">
                Google API Permissions
              </Link>
              <Link href="/contact" className="text-muted-foreground hover:text-foreground transition-colors" data-testid="link-footer-contact">
                {t("landing.footer.contact")}
              </Link>
            </div>
            <p className="text-sm text-muted-foreground">
              © {new Date().getFullYear()} HolaRevi. {t("landing.footer.rights")}
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}

client/src/components/review-demo.tsx.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import { Sparkles, Check, Star } from "lucide-react";
import { useLanguage, translations } from "@/lib/i18n";

type BusinessType =
  | "restaurant"
  | "hotel"
  | "nail_beauty"
  | "clinic"
  | "gym"
  | "car_repair"
  | "retail"
  | "cafe"
  | "vet"
  | "other";

interface Review {
  text: string;
  sentiment: "positive" | "negative";
  stars: number;
}

function StarRating({ count }: { count: number }) {
  return (
    <div className="flex gap-0.5">
      {[1, 2, 3, 4, 5].map((star) => (
        <Star
          key={star}
          className={`h-4 w-4 ${
            star <= count
              ? "fill-yellow-400 text-yellow-400"
              : "text-gray-300 dark:text-gray-600"
          }`}
        />
      ))}
    </div>
  );
}

export function ReviewDemo() {
  const { language } = useLanguage();
  const t = translations[language];

  const [businessType, setBusinessType] = useState<BusinessType>("restaurant");
  const [selectedReviewIndex, setSelectedReviewIndex] = useState<number | null>(
    null,
  );
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedReply, setGeneratedReply] = useState<string | null>(null);
  const [showDemoPopup, setShowDemoPopup] = useState(false);
  const [timeSaved, setTimeSaved] = useState(0);

  const reviewTexts = t.generator.reviews[businessType];
  const replyTexts = t.generator.replies[businessType];
  const businessLabels = t.generator.businessTypes;

  const reviews: Review[] = reviewTexts.map((text, index) => ({
    text,
    sentiment: index < 2 ? "positive" : "negative",
    stars: index === 0 ? 5 : index === 1 ? 5 : index === 2 ? 2 : 1,
  }));

  const handleBusinessTypeChange = (value: BusinessType) => {
    setBusinessType(value);
    setSelectedReviewIndex(null);
    setGeneratedReply(null);
  };

  const handleReviewSelect = (index: number) => {
    setSelectedReviewIndex(index);
    setGeneratedReply(null);
  };

  const handleGenerate = () => {
    if (selectedReviewIndex === null) return;

    setIsGenerating(true);
    setGeneratedReply(null);

    setTimeout(() => {
      const reply = replyTexts[selectedReviewIndex];
      setGeneratedReply(reply);
      setIsGenerating(false);
      setTimeSaved((prev) => prev + 4);
    }, 800);
  };

  const handleApprove = () => {
    setShowDemoPopup(true);
    setTimeout(() => setShowDemoPopup(false), 2000);
  };

  return (
    <section className="py-20 bg-muted/30">
      <div className="container mx-auto px-4">
        <div className="mx-auto max-w-2xl text-center mb-12">
          <Badge variant="secondary" className="mb-4">
            {t.generator.badge}
          </Badge>
          <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
            {t.generator.sectionTitle}
          </h2>
          <p className="mt-4 text-muted-foreground">
            {t.generator.sectionDescription}
          </p>
        </div>

        <div className="mx-auto max-w-2xl">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Sparkles className="h-5 w-5 text-primary" />
                {t.generator.cardTitle}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="business-type">{t.generator.businessTypeLabel}</Label>
                <Select
                  value={businessType}
                  onValueChange={(val) =>
                    handleBusinessTypeChange(val as BusinessType)
                  }
                >
                  <SelectTrigger
                    id="business-type"
                    data-testid="select-business-type"
                  >
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="restaurant">{businessLabels.restaurant}</SelectItem>
                    <SelectItem value="hotel">{businessLabels.hotel}</SelectItem>
                    <SelectItem value="nail_beauty">{businessLabels.nail_beauty}</SelectItem>
                    <SelectItem value="clinic">{businessLabels.clinic}</SelectItem>
                    <SelectItem value="gym">{businessLabels.gym}</SelectItem>
                    <SelectItem value="car_repair">{businessLabels.car_repair}</SelectItem>
                    <SelectItem value="retail">{businessLabels.retail}</SelectItem>
                    <SelectItem value="cafe">{businessLabels.cafe}</SelectItem>
                    <SelectItem value="vet">{businessLabels.vet}</SelectItem>
                    <SelectItem value="other">{businessLabels.other}</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-3">
                <Label>{t.generator.selectReviewLabel}</Label>
                <div className="grid gap-3">
                  {reviews.map((review, index) => (
                    <Card
                      key={index}
                      className={`cursor-pointer transition-all hover-elevate ${
                        selectedReviewIndex === index
                          ? "ring-2 ring-primary border-primary"
                          : ""
                      }`}
                      onClick={() => handleReviewSelect(index)}
                      data-testid={`card-review-${index + 1}`}
                    >
                      <CardContent className="p-4">
                        <div className="flex items-start justify-between gap-3">
                          <p className="text-sm leading-relaxed flex-1">
                            "{review.text}"
                          </p>
                          <StarRating count={review.stars} />
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>

              <Button
                onClick={handleGenerate}
                disabled={selectedReviewIndex === null || isGenerating}
                className="w-full"
                data-testid="button-generate"
              >
                {isGenerating ? (
                  <span className="animate-pulse">{t.generator.typingText}</span>
                ) : (
                  <>
                    <Sparkles className="mr-2 h-4 w-4" />
                    {t.generator.generateButton}
                  </>
                )}
              </Button>

              {generatedReply && (
                <div className="space-y-4 pt-4 border-t">
                  <div className="flex items-center justify-between">
                    <h3 className="font-semibold text-lg">{t.generator.responseTitle}</h3>
                    <Badge variant="secondary">
                      {businessLabels[businessType]}
                    </Badge>
                  </div>
                  <Card className="bg-primary/5 border-primary/20">
                    <CardContent className="pt-4">
                      <p
                        className="text-foreground leading-relaxed"
                        data-testid="text-generated-reply"
                      >
                        {generatedReply}
                      </p>
                    </CardContent>
                  </Card>
                  <div className="flex flex-wrap items-center justify-between gap-3">
                    <Button
                      onClick={handleApprove}
                      className="flex-shrink-0"
                      data-testid="button-approve"
                    >
                      <Check className="mr-2 h-4 w-4" />
                      {t.generator.approveButton}
                    </Button>
                    <span
                      className="text-sm text-muted-foreground"
                      data-testid="text-time-saved"
                    >
                      {t.generator.timeSaved} <strong>{timeSaved}</strong> {t.generator.timeUnit}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>

      {showDemoPopup && (
        <div className="fixed inset-0 flex items-center justify-center z-50 bg-black/50">
          <Card className="max-w-sm mx-4 animate-in fade-in zoom-in duration-200">
            <CardContent className="pt-6 text-center">
              <p className="text-lg font-medium">{t.generator.demoPopupTitle}</p>
              <p className="text-muted-foreground mt-2">
                {t.generator.demoPopupDescription}
              </p>
            </CardContent>
          </Card>
        </div>
      )}
    </section>
  );
}

client/src/pages/admin-contacts.tsx.content:
import { useEffect, useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  LogOut,
  Mail,
  Phone,
  Building,
  Calendar,
  Loader2,
  MessageSquare,
  User,
  Rocket,
  Power,
  Trash2,
  BarChart3,
  Home,
} from "lucide-react";
import { Link } from "wouter";
import { useToast } from "@/hooks/use-toast";

interface Contact {
  id: string;
  name: string;
  company: string;
  email: string;
  phone: string;
  message: string;
  createdAt: string;
}

export default function AdminContacts() {
  const { toast } = useToast();
  const [, setLocation] = useLocation();
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState("");
  const [prelaunchEnabled, setPrelaunchEnabled] = useState<boolean | null>(
    null,
  );
  const [isTogglingPrelaunch, setIsTogglingPrelaunch] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null); // 👈 para desactivar botón mientras borra

  useEffect(() => {
    checkAuthAndFetchContacts();
    fetchPrelaunchStatus();
  }, []);

  const fetchPrelaunchStatus = async () => {
    try {
      const response = await fetch("/api/admin/prelaunch-status", {
        credentials: "include",
      });
      const data = await response.json();
      if (data.success) {
        setPrelaunchEnabled(data.prelaunchEnabled);
      }
    } catch (err) {
      console.error("Failed to fetch prelaunch status:", err);
    }
  };

  const togglePrelaunch = async () => {
    if (prelaunchEnabled === null) return;

    setIsTogglingPrelaunch(true);
    try {
      const endpoint = prelaunchEnabled
        ? "/api/admin/disable-prelaunch"
        : "/api/admin/enable-prelaunch";

      const response = await fetch(endpoint, {
        method: "POST",
        credentials: "include",
      });

      const data = await response.json();

      if (data.success) {
        setPrelaunchEnabled(!prelaunchEnabled);
        toast({
          title: prelaunchEnabled
            ? "Prelaunch desactivado"
            : "Prelaunch activado",
          description: prelaunchEnabled
            ? "El sitio ahora es accesible para todos los usuarios."
            : "El sitio ahora muestra la página de prelaunch.",
        });
      } else {
        toast({
          title: "Error",
          description:
            data.message || "No se pudo cambiar el estado del prelaunch.",
          variant: "destructive",
        });
      }
    } catch (err) {
      toast({
        title: "Error",
        description: "Ocurrió un error al cambiar el estado del prelaunch.",
        variant: "destructive",
      });
    } finally {
      setIsTogglingPrelaunch(false);
    }
  };

  const checkAuthAndFetchContacts = async () => {
    try {
      const sessionResponse = await fetch("/api/admin/session", {
        credentials: "include",
      });
      const sessionData = await sessionResponse.json();

      if (!sessionData.authenticated) {
        setLocation("/admin/login");
        return;
      }

      const response = await fetch("/api/admin/contacts", {
        credentials: "include",
      });

      if (response.status === 401) {
        setLocation("/admin/login");
        return;
      }

      const data = await response.json();

      if (data.success) {
        setContacts(data.contacts);
      } else {
        setError("Failed to load contacts");
      }
    } catch (err) {
      setError("An error occurred while loading contacts");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      await fetch("/api/admin/logout", {
        method: "POST",
        credentials: "include",
      });
      setLocation("/admin/login");
    } catch (err) {
      console.error("Logout failed:", err);
    }
  };

  const handleDelete = async (id: string) => {
    const confirmed = window.confirm(
      "¿Seguro que quieres eliminar este contacto? Esta acción no se puede deshacer.",
    );
    if (!confirmed) return;

    try {
      setDeletingId(id);
      const response = await fetch(`/api/admin/contacts/${id}`, {
        method: "DELETE",
        credentials: "include",
      });

      const data = await response.json();

      if (data.success) {
        setContacts((prev) => prev.filter((c) => c.id !== id));
        toast({
          title: "Contacto eliminado",
          description: "Contacto eliminado correctamente.",
        });
      } else {
        toast({
          title: "Error",
          description: data.message || "No se pudo borrar el contacto. Inténtalo de nuevo.",
          variant: "destructive",
        });
      }
    } catch (err) {
      toast({
        title: "Error",
        description: "No se pudo borrar el contacto. Inténtalo de nuevo.",
        variant: "destructive",
      });
    } finally {
      setDeletingId(null);
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b bg-card">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between gap-4 flex-wrap">
          <div>
            <h1 className="text-2xl font-bold" data-testid="text-title">
              Contact Submissions
            </h1>
            <p className="text-muted-foreground text-sm">
              {contacts.length} submission{contacts.length !== 1 ? "s" : ""}
            </p>
          </div>
          <div className="flex items-center gap-3 flex-wrap">
            {prelaunchEnabled !== null && (
              <div className="flex items-center gap-2">
                <Badge
                  variant={prelaunchEnabled ? "default" : "secondary"}
                  className="flex items-center gap-1"
                  data-testid="badge-prelaunch-status"
                >
                  <Rocket className="h-3 w-3" />
                  {prelaunchEnabled ? "Prelaunch activo" : "Prelaunch inactivo"}
                </Badge>
                <Button
                  variant={prelaunchEnabled ? "destructive" : "default"}
                  size="sm"
                  onClick={togglePrelaunch}
                  disabled={isTogglingPrelaunch}
                  data-testid="button-toggle-prelaunch"
                >
                  {isTogglingPrelaunch ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <>
                      <Power className="h-4 w-4 mr-1" />
                      {prelaunchEnabled
                        ? "Desactivar prelaunch"
                        : "Activar prelaunch"}
                    </>
                  )}
                </Button>
              </div>
            )}
            <Button
              variant="outline"
              asChild
              data-testid="button-home"
            >
              <Link href="/admin">
                <Home className="h-4 w-4 mr-2" />
                Home
              </Link>
            </Button>
            <Button
              variant="default"
              asChild
              data-testid="button-affiliates"
            >
              <Link href="/admin/affiliates">
                <User className="h-4 w-4 mr-2" />
                Affiliates
              </Link>
            </Button>
            <Button
              variant="outline"
              asChild
              data-testid="button-analytics"
            >
              <Link href="/admin/analytics">
                <BarChart3 className="h-4 w-4 mr-2" />
                Analytics
              </Link>
            </Button>
            <Button
              variant="ghost"
              onClick={handleLogout}
              data-testid="button-logout"
            >
              <LogOut className="h-4 w-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-6">
        {error && (
          <div
            className="mb-4 p-4 text-destructive bg-destructive/10 rounded-md"
            data-testid="status-error"
          >
            {error}
          </div>
        )}

        {contacts.length === 0 ? (
          <Card>
            <CardContent className="py-12 text-center">
              <MessageSquare className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
              <p className="text-muted-foreground" data-testid="text-empty">
                No contact submissions yet
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-4">
            {contacts.map((contact) => (
              <Card key={contact.id} data-testid={`card-contact-${contact.id}`}>
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between gap-4 flex-wrap">
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4 text-muted-foreground" />
                      <CardTitle
                        className="text-lg"
                        data-testid={`text-name-${contact.id}`}
                      >
                        {contact.name}
                      </CardTitle>
                    </div>

                    <div className="flex items-center gap-2">
                      <Badge
                        variant="outline"
                        className="flex items-center gap-1"
                      >
                        <Calendar className="h-3 w-3" />
                        {formatDate(contact.createdAt)}
                      </Badge>

                      <Button
                        variant="outline"
                        size="icon"
                        onClick={() => handleDelete(contact.id)}
                        disabled={deletingId === contact.id}
                        data-testid={`button-delete-${contact.id}`}
                      >
                        {deletingId === contact.id ? (
                          <Loader2 className="h-4 w-4 animate-spin" />
                        ) : (
                          <Trash2 className="h-4 w-4 text-destructive" />
                        )}
                      </Button>
                    </div>
                  </div>

                  <CardDescription className="flex flex-wrap gap-4 mt-2">
                    {contact.company && (
                      <span className="flex items-center gap-1">
                        <Building className="h-3 w-3" />
                        {contact.company}
                      </span>
                    )}
                    <span className="flex items-center gap-1">
                      <Mail className="h-3 w-3" />
                      <a
                        href={`mailto:${contact.email}`}
                        className="hover:underline"
                        data-testid={`link-email-${contact.id}`}
                      >
                        {contact.email}
                      </a>
                    </span>
                    {contact.phone && (
                      <span className="flex items-center gap-1">
                        <Phone className="h-3 w-3" />
                        <a
                          href={`tel:${contact.phone}`}
                          className="hover:underline"
                          data-testid={`link-phone-${contact.id}`}
                        >
                          {contact.phone}
                        </a>
                      </span>
                    )}
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <p
                    className="text-sm whitespace-pre-wrap"
                    data-testid={`text-message-${contact.id}`}
                  >
                    {contact.message}
                  </p>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

server/googleBusiness.ts.content:
import { storage } from "./storage";
import type { Restaurant, InsertReview } from "@shared/schema";
import { generateReviewReply } from "./openai";
import { canSendReply, getMonthlyReplyUsage, PLAN_ERROR_CODES } from "./planHelpers";

const GOOGLE_API_BASE = "https://mybusinessbusinessinformation.googleapis.com/v1";
const GOOGLE_ACCOUNT_API = "https://mybusinessaccountmanagement.googleapis.com/v1";

interface GoogleTokens {
  accessToken: string;
  refreshToken: string;
  expiresAt: Date;
}

async function refreshAccessToken(restaurant: Restaurant): Promise<string | null> {
  const clientId = process.env.GOOGLE_CLIENT_ID;
  const clientSecret = process.env.GOOGLE_CLIENT_SECRET;

  if (!clientId || !clientSecret || !restaurant.googleRefreshToken) {
    console.error("[Google Business] Missing credentials or refresh token");
    return null;
  }

  try {
    const response = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        client_id: clientId,
        client_secret: clientSecret,
        refresh_token: restaurant.googleRefreshToken,
        grant_type: "refresh_token",
      }),
    });

    if (!response.ok) {
      const error = await response.text();
      console.error("[Google Business] Token refresh failed:", error);
      return null;
    }

    const tokens = await response.json();
    const expiresAt = new Date();
    expiresAt.setSeconds(expiresAt.getSeconds() + tokens.expires_in);

    await storage.updateRestaurant(restaurant.id, {
      googleAccessToken: tokens.access_token,
      googleTokenExpiresAt: expiresAt,
    });

    console.log(`[Google Business] Token refreshed for restaurant ${restaurant.id}`);
    return tokens.access_token;
  } catch (error) {
    console.error("[Google Business] Token refresh error:", error);
    return null;
  }
}

async function getValidAccessToken(restaurant: Restaurant): Promise<string | null> {
  if (!restaurant.googleAccessToken) {
    return null;
  }

  const now = new Date();
  const expiresAt = restaurant.googleTokenExpiresAt ? new Date(restaurant.googleTokenExpiresAt) : null;

  if (expiresAt && expiresAt > now) {
    return restaurant.googleAccessToken;
  }

  return await refreshAccessToken(restaurant);
}

export async function fetchGoogleAccounts(restaurant: Restaurant): Promise<any[]> {
  const accessToken = await getValidAccessToken(restaurant);
  if (!accessToken) {
    console.error("[Google Business] No valid access token");
    return [];
  }

  try {
    const response = await fetch(`${GOOGLE_ACCOUNT_API}/accounts`, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error(`[Google Business] Failed to fetch accounts - Status: ${response.status}, Error:`, errorText);

      // Parse error for more details
      try {
        const errorData = JSON.parse(errorText);
        console.error("[Google Business] Error details:", JSON.stringify(errorData, null, 2));

        // Check for common API access issues
        if (response.status === 403) {
          console.error("[Google Business] 403 FORBIDDEN - This usually means:");
          console.error("  1. Google Business Profile API is not enabled in your Google Cloud Console");
          console.error("  2. You haven't applied for/received Google Business Profile API access");
          console.error("  3. The API access request hasn't been approved yet");
        }
      } catch (e) {
        // Error is not JSON
      }
      return [];
    }

    const data = await response.json();
    console.log("[Google Business] Fetched accounts:", JSON.stringify(data, null, 2));

    // Handle case where user has no Business Profile accounts
    if (!data.accounts || data.accounts.length === 0) {
      console.log("[Google Business] No accounts found - User may not have Business Profile API access approved");
    }

    return data.accounts || [];
  } catch (error) {
    console.error("[Google Business] Error fetching accounts:", error);
    return [];
  }
}

export async function fetchGoogleLocations(restaurant: Restaurant, accountId: string): Promise<any[]> {
  const accessToken = await getValidAccessToken(restaurant);
  if (!accessToken) {
    console.error("[Google Business] No valid access token");
    return [];
  }

  try {
    // Ensure accountId is in the correct format (without 'accounts/' prefix for the URL)
    const cleanAccountId = accountId.replace(/^accounts\//, '');

    // Build URL with required readMask parameter
    // The readMask specifies which fields to return
    const url = new URL(`${GOOGLE_API_BASE}/accounts/${cleanAccountId}/locations`);
    url.searchParams.set('readMask', 'name,title,storefrontAddress,metadata');

    console.log(`[Google Business] Fetching locations from: ${url.toString()}`);

    const response = await fetch(url.toString(), {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error(`[Google Business] Failed to fetch locations - Status: ${response.status}`);
      console.error(`[Google Business] Error response:`, errorText);

      try {
        const errorData = JSON.parse(errorText);
        console.error("[Google Business] Error details:", JSON.stringify(errorData, null, 2));

        if (response.status === 403) {
          console.error("[Google Business] 403 FORBIDDEN - Possible causes:");
          console.error("  1. The account ID might be incorrect");
          console.error("  2. The user doesn't have access to this account");
          console.error("  3. The Business Profile API is not enabled");
        } else if (response.status === 404) {
          console.error("[Google Business] 404 NOT FOUND - The account might not exist or the format is wrong");
        }
      } catch (e) {
        // Error is not JSON
      }
      return [];
    }

    const data = await response.json();
    console.log("[Google Business] Fetched locations response:", JSON.stringify(data, null, 2));

    // Handle different response formats
    const locations = data.locations || [];
    console.log(`[Google Business] Found ${locations.length} locations`);

    return locations;
  } catch (error) {
    console.error("[Google Business] Error fetching locations:", error);
    return [];
  }
}

export async function fetchGoogleReviews(restaurant: Restaurant): Promise<any[]> {
  const accessToken = await getValidAccessToken(restaurant);
  if (!accessToken) {
    console.error("[Google Business] No valid access token");
    return [];
  }

  if (!restaurant.googleAccountId || !restaurant.googleLocationId) {
    console.error("[Google Business] Missing account or location ID for restaurant:", restaurant.id);
    return [];
  }

  try {
    const accountName = restaurant.googleAccountId.startsWith("accounts/") 
      ? restaurant.googleAccountId 
      : `accounts/${restaurant.googleAccountId}`;
    const locationName = restaurant.googleLocationId.startsWith("locations/")
      ? restaurant.googleLocationId
      : `locations/${restaurant.googleLocationId}`;

    const baseUrl = `https://mybusiness.googleapis.com/v4/${accountName}/${locationName}/reviews`;

    // Fetch ALL reviews with pagination - no limit for syncing
    const allReviews: any[] = [];
    let pageToken: string | undefined = undefined;
    let pageCount = 0;

    do {
      // Build URL with pagination parameters
      const url = new URL(baseUrl);
      url.searchParams.set('pageSize', '50'); // Max allowed by Google API
      if (pageToken) {
        url.searchParams.set('pageToken', pageToken);
      }

      console.log(`[Google Business] Fetching reviews page ${pageCount + 1} from: ${url.toString()}`);

      const response = await fetch(url.toString(), {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      });

      if (!response.ok) {
        const error = await response.text();
        console.error("[Google Business] Failed to fetch reviews:", error);
        break;
      }

      const data = await response.json();
      const pageReviews = data.reviews || [];
      allReviews.push(...pageReviews);

      // Get next page token for pagination
      pageToken = data.nextPageToken;
      pageCount++;

      console.log(`[Google Business] Page ${pageCount}: fetched ${pageReviews.length} reviews (total: ${allReviews.length})`);

    } while (pageToken); // Continue until no more pages

    console.log(`[Google Business] Fetched ALL ${allReviews.length} reviews across ${pageCount} page(s)`);
    return allReviews;
  } catch (error) {
    console.error("[Google Business] Error fetching reviews:", error);
    return [];
  }
}

function mapStarRating(starRating: string): number {
  const ratingMap: Record<string, number> = {
    ONE: 1,
    TWO: 2,
    THREE: 3,
    FOUR: 4,
    FIVE: 5,
  };
  return ratingMap[starRating] || 3;
}

function detectLanguage(text: string): string {
  if (!text) return "en";

  const spanishPatterns = /\b(muy|bueno|excelente|gracias|comida|servicio|restaurante|pero|porque|también|está|están)\b/i;
  const catalanPatterns = /\b(molt|bo|excel·lent|gràcies|menjar|servei|restaurant|però|perquè|també|està|estan)\b/i;

  if (catalanPatterns.test(text)) return "ca";
  if (spanishPatterns.test(text)) return "es";
  return "en";
}

function analyzeSentiment(rating: number, comment: string): string {
  if (rating >= 4) return "positive";
  if (rating <= 2) return "negative";
  return "neutral";
}

export async function syncReviewsForRestaurant(restaurant: Restaurant): Promise<{ synced: number; errors: number }> {
  console.log(`[Google Business] Starting review sync for restaurant: ${restaurant.name} (${restaurant.id})`);

  if (!restaurant.isConnected || !restaurant.googleAccountId || !restaurant.googleLocationId) {
    console.log(`[Google Business] Restaurant not fully connected, skipping sync`);
    return { synced: 0, errors: 0 };
  }

  const googleReviews = await fetchGoogleReviews(restaurant);
  let synced = 0;
  let errors = 0;

  for (const googleReview of googleReviews) {
    try {
      const googleReviewId = googleReview.reviewId || googleReview.name?.split("/").pop();

      const existingReview = await storage.getReviewByGoogleId(googleReviewId);
      if (existingReview) {
        console.log(`[Google Business] Review ${googleReviewId} already exists, skipping`);
        continue;
      }

      const rating = mapStarRating(googleReview.starRating);
      const comment = googleReview.comment || "";
      const language = detectLanguage(comment);
      const sentiment = analyzeSentiment(rating, comment);

      // Check if the review already has a business reply on Google
      // Google API returns reviewReply object with comment field for existing replies
      const existingGoogleReply = googleReview.reviewReply?.comment || null;
      const hasExistingReply = !!existingGoogleReply;

      const reviewData: InsertReview = {
        restaurantId: restaurant.id,
        googleReviewId,
        reviewerName: googleReview.reviewer?.displayName || "Google User",
        reviewerPhotoUrl: googleReview.reviewer?.profilePhotoUrl,
        rating,
        comment,
        language,
        sentiment,
        // If already has a reply on Google, mark as posted; otherwise pending
        replyStatus: hasExistingReply ? "posted" : "pending",
        // Store the existing reply if present
        postedReply: existingGoogleReply,
        repliedAt: hasExistingReply && googleReview.reviewReply?.updateTime 
          ? new Date(googleReview.reviewReply.updateTime) 
          : (hasExistingReply ? new Date() : undefined),
        reviewedAt: googleReview.createTime ? new Date(googleReview.createTime) : new Date(),
      };

      const savedReview = await storage.createReview(reviewData);

      if (hasExistingReply) {
        console.log(`[Google Business] Saved review ${savedReview.id} with existing Google reply (marked as posted)`);
        synced++;
        continue; // Skip AI generation for reviews that already have replies
      }

      console.log(`[Google Business] Saved review: ${savedReview.id}`);

      try {
        // Check plan limits before generating AI reply
        const user = await storage.getUser(restaurant.userId);
        if (!user) {
          console.log(`[Google Business] User not found for restaurant ${restaurant.id}, skipping AI reply`);
          synced++;
          continue;
        }

        // Check and possibly reset monthly usage
        const { used, needsReset } = getMonthlyReplyUsage(user);
        if (needsReset) {
          await storage.updateUserReplyUsage(user.id, 0, new Date());
        }

        const replyCheck = canSendReply(user);
        if (!replyCheck.allowed && !needsReset) {
          console.log(`[Google Business] User ${user.id} has reached reply limit (${replyCheck.current}/${replyCheck.limit}), skipping AI reply`);
          synced++;
          continue;
        }

        const aiReply = await generateReviewReply({
          reviewerName: reviewData.reviewerName || "Customer",
          rating,
          comment,
          restaurantName: restaurant.name,
          toneOfVoice: restaurant.toneOfVoice || "friendly",
        });

        await storage.updateReview(savedReview.id, {
          generatedReply: aiReply.reply,
          language: aiReply.language,
          sentiment: aiReply.sentiment,
        });

        console.log(`[Google Business] Generated AI reply for review: ${savedReview.id}`);

        // Increment usage after successful generation
        const currentUsed = needsReset ? 0 : (user.monthlyRepliesUsed || 0);
        await storage.updateUserReplyUsage(user.id, currentUsed + 1);

        if (restaurant.autoPostEnabled) {
          await postReplyToGoogle(restaurant, savedReview.id, aiReply.reply);
        }
      } catch (aiError) {
        console.error(`[Google Business] AI reply generation failed:`, aiError);
      }

      synced++;
    } catch (error) {
      console.error(`[Google Business] Error processing review:`, error);
      errors++;
    }
  }

  console.log(`[Google Business] Sync complete: ${synced} synced, ${errors} errors`);
  return { synced, errors };
}

export async function postReplyToGoogle(restaurant: Restaurant, reviewId: string, reply: string): Promise<boolean> {
  const accessToken = await getValidAccessToken(restaurant);
  if (!accessToken) {
    console.error("[Google Business] No valid access token for posting reply");
    return false;
  }

  const review = await storage.getReview(reviewId);
  if (!review || !review.googleReviewId) {
    console.error("[Google Business] Review not found or missing Google ID");
    return false;
  }

  try {
    const accountName = restaurant.googleAccountId?.startsWith("accounts/")
      ? restaurant.googleAccountId
      : `accounts/${restaurant.googleAccountId}`;
    const locationName = restaurant.googleLocationId?.startsWith("locations/")
      ? restaurant.googleLocationId
      : `locations/${restaurant.googleLocationId}`;

    const url = `https://mybusiness.googleapis.com/v4/${accountName}/${locationName}/reviews/${review.googleReviewId}/reply`;

    const response = await fetch(url, {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${accessToken}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ comment: reply }),
    });

    if (!response.ok) {
      const error = await response.text();
      console.error("[Google Business] Failed to post reply:", error);
      return false;
    }

    await storage.updateReview(reviewId, {
      postedReply: reply,
      replyStatus: "posted",
      repliedAt: new Date(),
    });

    console.log(`[Google Business] Reply posted for review: ${reviewId}`);
    return true;
  } catch (error) {
    console.error("[Google Business] Error posting reply:", error);
    return false;
  }
}

export async function syncAllConnectedRestaurants(): Promise<void> {
  console.log("[Google Business] Starting sync for all connected restaurants...");

  const connectedRestaurants = await storage.getConnectedRestaurants();
  console.log(`[Google Business] Found ${connectedRestaurants.length} connected restaurants`);

  for (const restaurant of connectedRestaurants) {
    try {
      await syncReviewsForRestaurant(restaurant);
    } catch (error) {
      console.error(`[Google Business] Error syncing restaurant ${restaurant.id}:`, error);
    }
  }

  console.log("[Google Business] Sync complete for all restaurants");
}

