export function getPlan(planId: PlanId): Plan {
  return PLANS[planId];
}

export function getPlanPrice(planId: PlanId, billingCycle: BillingCycle): number {
  const plan = PLANS[planId];
  if (plan.isCustomPricing) return 0;
  return billingCycle === "yearly" ? plan.price.yearly : plan.price.monthly;
}

export function getPlanMonthlyEquivalent(planId: PlanId, billingCycle: BillingCycle): number {
  const plan = PLANS[planId];
  if (plan.isCustomPricing) return 0;
  if (billingCycle === "yearly") {
    return Math.round((plan.price.yearly / 12) * 100) / 100;
  }
  return plan.price.monthly;
}

export function getStripePriceId(planId: PlanId, billingCycle: BillingCycle): string | null {
  const plan = PLANS[planId];
  if (plan.isCustomPricing) return null;

  // Always use the live price IDs
  return plan.price.stripePriceIds[billingCycle];
}

export function getPlanLimits(planId: PlanId): PlanLimits {
  return PLANS[planId].limits;
}

export function isUnlimited(value: number | "unlimited"): value is "unlimited" {
  return value === "unlimited";
}

export const YEARLY_DISCOUNT_PERCENT = 20;

