import { useQuery } from "@tanstack/react-query";
import { AdminAnalyticsLayout } from "@/components/admin-analytics-layout";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Loader2, Users, CreditCard, MessageSquare, Star, TrendingUp, TrendingDown } from "lucide-react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";

interface OverviewMetrics {
  totalSignups: number;
  activePayingCustomers: number;
  totalAiReplies: number;
  averageRating: number;
  signupsChange: number;
  customersChange: number;
  repliesChange: number;
}

interface ChartDataPoint {
  date: string;
  signups: number;
  replies: number;
}

interface OverviewResponse {
  success: boolean;
  metrics: OverviewMetrics;
  chartData: ChartDataPoint[];
}

function MetricCard({
  title,
  value,
  change,
  icon: Icon,
  format = "number",
  testId,
}: {
  title: string;
  value: number;
  change?: number;
  icon: React.ElementType;
  format?: "number" | "currency" | "rating";
  testId?: string;
}) {
  const formattedValue =
    format === "currency"
      ? `€${value.toLocaleString()}`
      : format === "rating"
        ? value.toFixed(1)
        : value.toLocaleString();

  return (
    <Card data-testid={testId}>
      <CardHeader className="flex flex-row items-center justify-between pb-2">
        <CardTitle className="text-sm font-medium text-muted-foreground">
          {title}
        </CardTitle>
        <Icon className="h-4 w-4 text-muted-foreground" />
      </CardHeader>
      <CardContent>
        <div className="text-2xl font-bold" data-testid={testId ? `${testId}-value` : undefined}>{formattedValue}</div>
        {change !== undefined && (
          <div className="flex items-center text-xs text-muted-foreground mt-1">
            {change >= 0 ? (
              <TrendingUp className="h-3 w-3 text-emerald-500 mr-1" />
