                        const revenue = (props?.payload as { revenue?: number })?.revenue || 0;
                        return [`${value} subs (€${revenue}/mo)`, name];
                      }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Plan Breakdown</CardTitle>
            <CardDescription>
              Detailed view of subscriptions and revenue by plan
