import { useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Lock, User, AlertCircle, Loader2 } from "lucide-react";

export default function AffiliateLogin() {
  const [, setLocation] = useLocation();
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    try {
      const response = await fetch("/api/affiliate/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, password }),
        credentials: "include",
      });

      const data = await response.json();

      if (response.ok && data.success) {
        setLocation("/affiliate/dashboard");
      } else {
        setError(data.message || "Invalid credentials");
      }
    } catch (err) {
      setError("An error occurred. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
            <Lock className="h-6 w-6 text-primary" />
          </div>
          <CardTitle className="text-2xl" data-testid="text-title">
            Affiliate Login
          </CardTitle>
          <CardDescription>
            Enter your credentials to access your affiliate dashboard
          </CardDescription>
        </CardHeader>

        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            {error && (
              <div
                className="flex items-center gap-2 p-3 text-sm text-destructive bg-destructive/10 rounded-md"
                data-testid="status-error"
              >
                <AlertCircle className="h-4 w-4" />
                {error}
              </div>
            )}

            <div className="space-y-2">
              <Label htmlFor="username">Username</Label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="username"
                  type="text"
                  placeholder="Enter username"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="pl-10"
                  required
                  disabled={isLoading}
                  data-testid="input-username"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="password"
                  type="password"
                  placeholder="Enter password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="pl-10"
                  required
                  disabled={isLoading}
                  data-testid="input-password"
                />
              </div>
            </div>

            <Button
              type="submit"
              className="w-full"
              disabled={isLoading}
              data-testid="button-login"
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Logging in...
                </>
              ) : (
                "Login"
              )}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/affiliate-dashboard.tsx.content:
import { useMemo, useState } from "react";
import { useLocation } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

import {
  Loader2,
  LogOut,
  Phone,
  Mail,
  MapPin,
  Globe,
  Building2,
  CheckCircle2,
  TrendingUp,
  Users,
} from "lucide-react";

type LeadStatus =
  | "pending"
  | "called"
  | "not_interested"
  | "call_later"
  | "sale_closed";

interface AffiliateMe {
  id: string;
  username: string;
  commissionPct: number;
  zone?: string | null;
  status: "active" | "paused";
}

interface Lead {
  id: string;
  businessName: string;
  city: string;
  category: string;
  totalReviews: number;
  unansweredReviews: number;
  avgRating: number;
  reviewsPerDay: number;
  replyPct: number;
  website?: string | null;

  address?: string | null;
  phone?: string | null;
  email?: string | null;
  googleMapsUrl?: string | null;

  status: LeadStatus;
  notes?: string | null;

  createdAt?: string;
  updatedAt?: string;
}

const statusLabel: Record<LeadStatus, string> = {
  pending: "Pending",
  called: "Called",
  not_interested: "Not interested",
  call_later: "Call later",
  sale_closed: "Sale closed",
};

const statusBadgeVariant = (s: LeadStatus) => {
  if (s === "sale_closed") return "default";
  if (s === "pending") return "secondary";
  if (s === "call_later") return "outline";
  if (s === "called") return "outline";
  return "destructive";
};

export default function AffiliateDashboard() {
  const { toast } = useToast();
  const [, setLocation] = useLocation();

  // Sale dialog
  const [saleLead, setSaleLead] = useState<Lead | null>(null);
  const [saleEmail, setSaleEmail] = useState("");
  const [salePlan, setSalePlan] = useState("49");
  const [saleComment, setSaleComment] = useState("");

  // Notes dialog
  const [notesLead, setNotesLead] = useState<Lead | null>(null);
  const [notesText, setNotesText] = useState("");

  // Fetch affiliate session/me
  const { data: me, isLoading: meLoading } = useQuery<AffiliateMe>({
    queryKey: ["/api/affiliate/me"],
    retry: false,
  });

  // If backend returns 401, we’ll redirect once we implement it.
  // For now this is harmless.
  const { data: leads, isLoading: leadsLoading } = useQuery<Lead[]>({
    queryKey: ["/api/affiliate/leads"],
    retry: false,
  });

  const stats = useMemo(() => {
    const list = leads || [];
    const assigned = list.length;
    const contacted = list.filter((l) => l.status !== "pending").length;
    const sales = list.filter((l) => l.status === "sale_closed").length;
    const conversion = assigned > 0 ? Math.round((sales / assigned) * 100) : 0;

    return { assigned, contacted, sales, conversion };
  }, [leads]);

  const logout = async () => {
    try {
      await fetch("/api/affiliate/logout", { method: "POST", credentials: "include" });
    } catch {}
    setLocation("/affiliate/login");
  };

  const updateStatus = useMutation({
    mutationFn: async (payload: { leadId: string; status: LeadStatus }) => {
      const res = await apiRequest(
        "PATCH",
        `/api/affiliate/leads/${payload.leadId}/status`,
        { status: payload.status },
      );
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/affiliate/leads"] });
    },
    onError: (err: any) => {
      toast({
        title: "Error",
        description: err?.message || "Could not update status",
        variant: "destructive",
      });
    },
  });

  const saveNotes = useMutation({
    mutationFn: async (payload: { leadId: string; notes: string }) => {
      const res = await apiRequest(
        "PATCH",
        `/api/affiliate/leads/${payload.leadId}/notes`,
        { notes: payload.notes },
      );
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/affiliate/leads"] });
      setNotesLead(null);
      setNotesText("");
      toast({ title: "Saved", description: "Notes updated." });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Could not save notes",
        variant: "destructive",
      });
    },
  });

  const submitSale = useMutation({
    mutationFn: async (payload: {
      leadId: string;
      businessEmail: string;
      planSold: number;
      comment?: string;
    }) => {
      const res = await apiRequest("POST", "/api/affiliate/sales", payload);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/affiliate/leads"] });
      setSaleLead(null);
      setSaleEmail("");
      setSalePlan("49");
      setSaleComment("");
      toast({
        title: "Sale submitted",
        description: "Your sale was submitted for admin validation.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Could not submit sale",
        variant: "destructive",
      });
    },
  });

  const openNotes = (lead: Lead) => {
    setNotesLead(lead);
    setNotesText(lead.notes || "");
  };

  const openSale = (lead: Lead) => {
    setSaleLead(lead);
    setSaleEmail(lead.email || "");
    setSalePlan("49");
    setSaleComment("");
  };

  if (meLoading || leadsLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b bg-card">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between gap-4 flex-wrap">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <Building2 className="h-5 w-5 text-muted-foreground" />
              Affiliate Dashboard
            </h1>
            <p className="text-muted-foreground text-sm">
              {me?.username ? `Logged in as ${me.username}` : " "}
              {me?.zone ? ` • Zone: ${me.zone}` : ""}
            </p>
          </div>

          <div className="flex items-center gap-2">
            <Button variant="outline" onClick={logout}>
              <LogOut className="h-4 w-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-6 space-y-6">
        {/* KPI cards */}
        <div className="grid gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-4">
          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Leads assigned</CardDescription>
              <CardTitle className="text-3xl">{stats.assigned}</CardTitle>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground flex items-center gap-2">
              <Users className="h-4 w-4" />
              Total leads in your list
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Leads contacted</CardDescription>
              <CardTitle className="text-3xl">{stats.contacted}</CardTitle>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground flex items-center gap-2">
              <TrendingUp className="h-4 w-4" />
              Any status != Pending
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Sales closed</CardDescription>
              <CardTitle className="text-3xl">{stats.sales}</CardTitle>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground flex items-center gap-2">
              <CheckCircle2 className="h-4 w-4" />
              Submitted sales
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardDescription>Conversion</CardDescription>
              <CardTitle className="text-3xl">{stats.conversion}%</CardTitle>
            </CardHeader>
            <CardContent className="text-sm text-muted-foreground">
              Sales / Assigned
            </CardContent>
          </Card>
        </div>

        {/* Leads list */}
        <Card>
          <CardHeader>
            <CardTitle>My Leads</CardTitle>
            <CardDescription>
              Update status, add notes, and report sales.
            </CardDescription>
          </CardHeader>

          <CardContent>
            {!leads || leads.length === 0 ? (
              <div className="py-10 text-center text-muted-foreground">
                No leads assigned yet.
              </div>
            ) : (
              <div className="space-y-3">
                {leads.map((lead) => (
                  <div
                    key={lead.id}
                    className="border rounded-lg p-4 flex flex-col gap-3"
                    data-testid={`lead-${lead.id}`}
                  >
                    <div className="flex items-start justify-between gap-4 flex-wrap">
                      <div className="min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="font-semibold truncate max-w-[520px]">
                            {lead.businessName}
                          </p>
                          <Badge variant={statusBadgeVariant(lead.status)}>
                            {statusLabel[lead.status]}
                          </Badge>
                        </div>

                        <div className="text-sm text-muted-foreground flex flex-wrap gap-4 mt-1">
                          <span className="flex items-center gap-1">
                            <MapPin className="h-3 w-3" />
                            {lead.city}
                          </span>
                          <span>{lead.category}</span>
                          <span>⭐ {lead.avgRating.toFixed(1)}</span>
                          <span>{lead.totalReviews} reviews</span>
                          <span>{lead.unansweredReviews} unanswered</span>
                          <span>{lead.reviewsPerDay.toFixed(1)}/day</span>
                          <span>{lead.replyPct.toFixed(0)}% replied</span>
                        </div>

                        <div className="text-sm text-muted-foreground flex flex-wrap gap-4 mt-2">
                          {lead.phone && (
                            <a
                              href={`tel:${lead.phone}`}
                              className="flex items-center gap-1 hover:underline"
                            >
                              <Phone className="h-3 w-3" />
                              {lead.phone}
                            </a>
                          )}
                          {lead.email && (
                            <a
                              href={`mailto:${lead.email}`}
                              className="flex items-center gap-1 hover:underline"
                            >
                              <Mail className="h-3 w-3" />
                              {lead.email}
                            </a>
                          )}
                          {lead.website && (
                            <a
                              href={lead.website}
                              target="_blank"
                              rel="noreferrer"
                              className="flex items-center gap-1 hover:underline"
                            >
                              <Globe className="h-3 w-3" />
                              Website
                            </a>
                          )}
                          {lead.googleMapsUrl && (
                            <a
                              href={lead.googleMapsUrl}
                              target="_blank"
                              rel="noreferrer"
                              className="flex items-center gap-1 hover:underline"
                            >
                              <MapPin className="h-3 w-3" />
                              Maps
                            </a>
                          )}
                        </div>
                      </div>

                      <div className="flex items-center gap-2 flex-wrap">
                        <Select
                          value={lead.status}
                          onValueChange={(v) =>
                            updateStatus.mutate({
                              leadId: lead.id,
                              status: v as LeadStatus,
                            })
                          }
                        >
                          <SelectTrigger className="w-[170px]">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="pending">Pending</SelectItem>
                            <SelectItem value="called">Called</SelectItem>
                            <SelectItem value="not_interested">
                              Not interested
                            </SelectItem>
                            <SelectItem value="call_later">
                              Call later
                            </SelectItem>
                            <SelectItem value="sale_closed">
                              Sale closed
                            </SelectItem>
                          </SelectContent>
                        </Select>

                        <Button variant="outline" onClick={() => openNotes(lead)}>
                          Notes
                        </Button>

                        <Button onClick={() => openSale(lead)}>
                          Report sale
                        </Button>
                      </div>
                    </div>

                    {lead.notes && (
                      <div className="text-sm bg-muted/40 rounded-md p-3">
                        <span className="font-medium">Notes:</span>{" "}
                        <span className="text-muted-foreground whitespace-pre-wrap">
                          {lead.notes}
                        </span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </main>

      {/* Notes dialog */}
      <Dialog open={!!notesLead} onOpenChange={(o) => !o && setNotesLead(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Lead notes</DialogTitle>
            <DialogDescription>
              Save private notes about your call/follow-up.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-2">
            <Label>Notes</Label>
            <Textarea
              value={notesText}
              onChange={(e) => setNotesText(e.target.value)}
              placeholder="Spoke with the manager, call back Thursday morning..."
              rows={6}
            />
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setNotesLead(null)}>
              Cancel
            </Button>
            <Button
              onClick={() =>
                notesLead &&
                saveNotes.mutate({ leadId: notesLead.id, notes: notesText })
              }
              disabled={saveNotes.isPending}
            >
              {saveNotes.isPending && (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              )}
              Save
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Sale dialog */}
      <Dialog open={!!saleLead} onOpenChange={(o) => !o && setSaleLead(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Report sale</DialogTitle>
            <DialogDescription>
              Submit a sale for admin validation.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="space-y-2">
              <Label>Business email</Label>
              <Input
                value={saleEmail}
                onChange={(e) => setSaleEmail(e.target.value)}
                placeholder="owner@business.com"
              />
            </div>

            <div className="space-y-2">
              <Label>Plan sold (€)</Label>
              <Select value={salePlan} onValueChange={setSalePlan}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="49">€49 (Local)</SelectItem>
                  <SelectItem value="99">€99 (Pro)</SelectItem>
                  <SelectItem value="199">€199 (Business)</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Comments (optional)</Label>
              <Textarea
                value={saleComment}
                onChange={(e) => setSaleComment(e.target.value)}
                placeholder="Any extra context for validation..."
                rows={4}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setSaleLead(null)}>
              Cancel
            </Button>
            <Button
              onClick={() =>
                saleLead &&
                submitSale.mutate({
                  leadId: saleLead.id,
                  businessEmail: saleEmail,
                  planSold: Number(salePlan),
                  comment: saleComment || undefined,
                })
              }
              disabled={!saleEmail || submitSale.isPending}
            >
              {submitSale.isPending && (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              )}
              Submit
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/select-plan.tsx.content:
import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Check, Loader2, MapPin, Zap, Building2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { PLANS, type PlanId, type BillingCycle } from "@shared/plans";
import { LandingHeader } from "@/components/landing-header";
import { useLanguage } from "@/lib/i18n";

const planIcons: Record<string, typeof MapPin> = {
  local: MapPin,
  pro: Zap,
  business: Building2,
};

const planColors: Record<string, string> = {
  local: "text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-950",
  pro: "text-primary bg-primary/10",
  business: "text-amber-600 dark:text-amber-400 bg-amber-100 dark:bg-amber-950",
};

export default function SelectPlan() {
  const { toast } = useToast();
  const { t } = useLanguage();
  const [billingCycle, setBillingCycle] = useState<BillingCycle>("monthly");

  // Check if user is eligible for Pro trial
  const { data: trialEligibility } = useQuery<{ canUseProTrial: boolean; hasUsedProTrial: boolean }>({
    queryKey: ["/api/trial-eligibility"],
  });

  const trialCheckoutMutation = useMutation({
    mutationFn: async ({ planId, billingCycle }: { planId: PlanId; billingCycle: BillingCycle }) => {
      const response = await apiRequest("POST", "/api/checkout/trial", { 
        planId, 
        billingCycle
      });
      const data = await response.json();
      if (!response.ok) {
        throw new Error(data.message || "Failed to start checkout");
      }
      return data;
    },
    onSuccess: (data) => {
      if (data.url) {
        window.location.href = data.url;
      }
    },
    onError: (error: Error) => {
      toast({ title: t("common.error"), description: error.message || "Failed to start checkout", variant: "destructive" });
    },
  });

  const subscribeCheckoutMutation = useMutation({
    mutationFn: async ({ planId, billingCycle }: { planId: PlanId; billingCycle: BillingCycle }) => {
      const response = await apiRequest("POST", "/api/checkout", { 
        planId, 
        billingCycle
      });
      const data = await response.json();
      if (!response.ok) {
        throw new Error(data.message || "Failed to start checkout");
      }
      return data;
    },
    onSuccess: (data) => {
      if (data.enterprise) {
        window.location.href = data.redirectTo || "/contact";
      } else if (data.url) {
        window.location.href = data.url;
      }
    },
    onError: (error: Error) => {
      toast({ title: t("common.error"), description: error.message || "Failed to start checkout", variant: "destructive" });
    },
  });

  const handlePlanSelect = (planId: PlanId) => {
    // Local and Pro (if eligible) use trial checkout
    if (planId === "local") {
      trialCheckoutMutation.mutate({ planId, billingCycle });
    } else if (planId === "pro" && trialEligibility?.canUseProTrial) {
      trialCheckoutMutation.mutate({ planId, billingCycle });
    } else {
      subscribeCheckoutMutation.mutate({ planId, billingCycle });
    }
  };

  const canUseProTrial = trialEligibility?.canUseProTrial ?? false;

  const isCheckoutPending = trialCheckoutMutation.isPending || subscribeCheckoutMutation.isPending;

  const getPrice = (planId: PlanId) => {
    const plan = PLANS[planId];
    if (billingCycle === "yearly") {
      return Math.round((plan.price.yearly / 12) * 100) / 100;
    }
    return plan.price.monthly;
  };

  const plans = ["local", "pro", "business"] as PlanId[];

  const getPlanName = (planId: PlanId) => {
    return t(`selectPlan.plans.${planId}.name`);
  };

  const getPlanDescription = (planId: PlanId) => {
    return t(`selectPlan.plans.${planId}.description`);
  };

  const getPlanFeatures = (planId: PlanId): string[] => {
    const featureKeys: Record<PlanId, string[]> = {
      local: ["location", "newReplies", "pastReplies", "mode", "analytics", "users"],
      pro: ["locations", "newReplies", "pastReplies", "analytics", "priority", "users"],
      business: ["locationsIncluded", "extraLocation", "dashboard", "team", "permissions", "sla"],
      enterprise: ["api", "crm", "automations", "auditLogs", "reporting", "sla"],
    };
    return featureKeys[planId].map(key => t(`selectPlan.plans.${planId}.features.${key}`));
  };

  return (
    <div className="min-h-screen bg-background">
      <LandingHeader showLoginButton={false} />
      <div className="flex flex-col items-center justify-center p-6">
        <div className="max-w-4xl w-full space-y-8">
          <div className="text-center">
            <h1 className="text-3xl font-bold" data-testid="text-select-plan-title">{t("selectPlan.title")}</h1>
            <p className="text-muted-foreground mt-2">{t("selectPlan.subtitle")}</p>
          </div>

        <div className="flex items-center justify-center gap-3">
          <Label htmlFor="billing-toggle">{t("selectPlan.monthly")}</Label>
          <Switch
            id="billing-toggle"
            checked={billingCycle === "yearly"}
            onCheckedChange={(checked) => setBillingCycle(checked ? "yearly" : "monthly")}
            data-testid="switch-billing-cycle"
          />
          <Label htmlFor="billing-toggle">{t("selectPlan.yearly")} <Badge variant="secondary">{t("selectPlan.save20")}</Badge></Label>
        </div>

        <div className="grid md:grid-cols-3 gap-6">
          {plans.map((planId) => {
            const plan = PLANS[planId];
            const Icon = planIcons[planId];
            return (
              <Card key={planId} className={`relative ${plan.isPopular ? "border-primary border-2" : ""}`} data-testid={`card-plan-${planId}`}>
                {plan.isPopular && <Badge className="absolute -top-3 left-1/2 -translate-x-1/2">{t("selectPlan.mostPopular")}</Badge>}
                <CardHeader>
                  <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${planColors[planId]}`}>
                    <Icon className="h-6 w-6" />
                  </div>
                  <CardTitle className="mt-4">{getPlanName(planId)}</CardTitle>
                  <CardDescription>{getPlanDescription(planId)}</CardDescription>
                  <div className="mt-4">
                    <span className="text-3xl font-bold" data-testid={`text-price-${planId}`}>€{getPrice(planId)}</span>
                    <span className="text-muted-foreground">{t("selectPlan.perMonth")}</span>
                  </div>
                </CardHeader>
                <CardContent>
                  <ul className="space-y-2">
                    {getPlanFeatures(planId).map((feature, i) => (
                      <li key={i} className="flex items-center gap-2 text-sm">
                        <Check className="h-4 w-4 text-primary" />
                        {feature}
                      </li>
                    ))}
                  </ul>
                  <Button
                    className="w-full mt-6"
                    onClick={() => handlePlanSelect(planId)}
                    disabled={isCheckoutPending}
                    data-testid={`button-select-${planId}`}
                  >
                    {isCheckoutPending ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                    {planId === "local" ? t("selectPlan.startFreeTrial") : 
                     (planId === "pro" && canUseProTrial) ? t("selectPlan.start3DayTrial") : 
                     t("selectPlan.subscribe")}
                  </Button>
                  {planId === "pro" && canUseProTrial && (
                    <p className="text-xs text-center text-muted-foreground mt-2" data-testid="text-pro-trial-info">
                      {t("selectPlan.proTrialInfo")}
                    </p>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
        </div>
      </div>
    </div>
  );
}

