import { useQuery, useMutation } from "@tanstack/react-query";
import { useLanguage } from "@/lib/i18n";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useState } from "react";
import { 
  Sparkles, 
  TrendingUp, 
  TrendingDown, 
  Minus, 
  ThumbsUp, 
  ThumbsDown,
  Lightbulb,
  MessageSquare,
  AlertCircle,
  RefreshCw,
  Loader2,
  Clock,
  Languages,
  Coins,
} from "lucide-react";
import type { Restaurant } from "@shared/schema";
import { format } from "date-fns";
import { es, ca, enUS } from "date-fns/locale";

interface ReviewSummaryData {
  overallSentiment: "positive" | "neutral" | "negative" | "mixed";
  sentimentScore: number;
  keyThemes: Array<{
    theme: string;
    sentiment: "positive" | "neutral" | "negative";
    count: number;
    examples: string[];
  }>;
  trends: {
    improving: string[];
    declining: string[];
    consistent: string[];
  };
  recommendations: string[];
  summary: string;
  reviewCount: number;
  analyzedCount: number;
  generatedAt?: string;
  language?: string;
}

export default function ReviewSummary() {
  const { t, language: uiLanguage } = useLanguage();
  const [selectedRestaurant, setSelectedRestaurant] = useState<string>("all");
  const [summaryLanguage, setSummaryLanguage] = useState<string>("es");

  const { data: restaurants } = useQuery<Restaurant[]>({
    queryKey: ["/api/restaurants"],
  });

  const { data: summary, isLoading, error, refetch } = useQuery<ReviewSummaryData | null>({
    queryKey: ["/api/reviews/summary", selectedRestaurant !== "all" ? selectedRestaurant : undefined, summaryLanguage],
    queryFn: async () => {
      const params = new URLSearchParams();
      if (selectedRestaurant !== "all") {
        params.set("restaurantId", selectedRestaurant);
      }
      params.set("language", summaryLanguage);
      const response = await fetch(`/api/reviews/summary?${params.toString()}`, {
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to fetch summary");
      return response.json();
    },
  });

  const generateMutation = useMutation({
    mutationFn: async () => {
      const body: any = { language: summaryLanguage };
      if (selectedRestaurant !== "all") {
        body.restaurantId = selectedRestaurant;
      }
      const res = await apiRequest("POST", "/api/reviews/summary/generate", body);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ 
        queryKey: ["/api/reviews/summary", selectedRestaurant !== "all" ? selectedRestaurant : undefined, summaryLanguage] 
      });
    },
  });

  const getSentimentColor = (sentiment: string) => {
    switch (sentiment) {
      case "positive": return "text-green-600 dark:text-green-400";
      case "negative": return "text-red-600 dark:text-red-400";
      case "mixed": return "text-amber-600 dark:text-amber-400";
      default: return "text-muted-foreground";
    }
  };

  const getSentimentBadge = (sentiment: string) => {
    switch (sentiment) {
      case "positive": return "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200";
      case "negative": return "bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200";
      case "mixed": return "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200";
      default: return "bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-200";
    }
  };

  const getSentimentIcon = (sentiment: string) => {
    switch (sentiment) {
      case "positive": return <ThumbsUp className="h-4 w-4" />;
      case "negative": return <ThumbsDown className="h-4 w-4" />;
      default: return <Minus className="h-4 w-4" />;
    }
  };

  const getDateLocale = () => {
    switch (uiLanguage) {
      case "es": return es;
      case "ca": return ca;
      default: return enUS;
    }
  };

  const formatGeneratedDate = (dateString: string) => {
    return format(new Date(dateString), "PPpp", { locale: getDateLocale() });
  };

  const getLanguageLabel = (lang: string) => {
    switch (lang) {
      case "es": return "Español";
      case "ca": return "Català";
      case "en": return "English";
      default: return lang.toUpperCase();
    }
  };

  if (isLoading) {
    return (
      <div className="p-6 space-y-6">
        <div className="flex flex-col gap-2">
          <Skeleton className="h-8 w-64" />
          <Skeleton className="h-4 w-96" />
        </div>
        <div className="flex gap-4">
          <Skeleton className="h-10 w-[200px]" />
          <Skeleton className="h-10 w-[150px]" />
          <Skeleton className="h-10 w-[180px]" />
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-6">
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <AlertCircle className="h-12 w-12 text-muted-foreground mb-4" />
            <p className="text-muted-foreground">{t("reviewSummary.error")}</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex flex-col gap-4">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2" data-testid="text-review-summary-title">
            <Sparkles className="h-6 w-6 text-primary" />
            {t("reviewSummary.title")}
          </h1>
          <p className="text-muted-foreground mt-1">
            {t("reviewSummary.subtitle")}
          </p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          {restaurants && restaurants.length > 1 && (
            <Select value={selectedRestaurant} onValueChange={setSelectedRestaurant}>
              <SelectTrigger className="w-[200px]" data-testid="select-restaurant-filter">
                <SelectValue placeholder={t("reviewSummary.allLocations")} />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">{t("reviewSummary.allLocations")}</SelectItem>
                {restaurants.map((r) => (
                  <SelectItem key={r.id} value={r.id}>{r.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}

          <Select value={summaryLanguage} onValueChange={setSummaryLanguage}>
            <SelectTrigger className="w-[160px]" data-testid="select-summary-language">
              <Languages className="h-4 w-4 mr-2" />
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="es">Español</SelectItem>
              <SelectItem value="ca">Català</SelectItem>
              <SelectItem value="en">English</SelectItem>
            </SelectContent>
          </Select>

          <Button
            onClick={() => generateMutation.mutate()}
            disabled={generateMutation.isPending}
            data-testid="button-generate-summary"
          >
            {generateMutation.isPending ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                {t("reviewSummary.generating")}
              </>
            ) : summary ? (
              <>
                <RefreshCw className="h-4 w-4 mr-2" />
                {t("reviewSummary.regenerate")}
              </>
            ) : (
              <>
                <Sparkles className="h-4 w-4 mr-2" />
                {t("reviewSummary.generate")}
              </>
            )}
          </Button>
        </div>

        <div className="flex items-center gap-2 text-sm text-muted-foreground">

        </div>
      </div>

      {!summary ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <MessageSquare className="h-12 w-12 text-muted-foreground mb-4" />
            <p className="text-lg font-medium mb-2">{t("reviewSummary.noSummary.title")}</p>
            <p className="text-muted-foreground text-center max-w-md">
              {t("reviewSummary.noSummary.description")}
            </p>
          </CardContent>
        </Card>
      ) : (
        <>
          <Card className="bg-gradient-to-r from-primary/5 to-primary/10 border-primary/20">
            <CardHeader>
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2">
                <CardTitle className="flex items-center gap-2">
                  <Sparkles className="h-5 w-5 text-primary" />
                  {t("reviewSummary.executiveSummary")}
                </CardTitle>
                {summary.generatedAt && (
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Clock className="h-4 w-4" />
                    <span>{formatGeneratedDate(summary.generatedAt)}</span>
                    <Badge variant="outline" className="ml-1">
                      {getLanguageLabel(summary.language || summaryLanguage)}
                    </Badge>
                  </div>
                )}
              </div>
            </CardHeader>
            <CardContent>
              <p className="text-foreground leading-relaxed" data-testid="text-summary">
                {summary.summary}
              </p>
              <div className="flex items-center gap-4 mt-4 text-sm text-muted-foreground">
                <span>{t("reviewSummary.basedOn")} {summary.analyzedCount} {t("reviewSummary.reviews")}</span>
                <span>|</span>
                <span>{t("reviewSummary.totalReviews")}: {summary.reviewCount}</span>
              </div>
            </CardContent>
          </Card>

          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            <Card>
              <CardHeader>
                <CardTitle>{t("reviewSummary.overallSentiment")}</CardTitle>
                <CardDescription>{t("reviewSummary.sentimentDescription")}</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center justify-between">
                  <Badge className={getSentimentBadge(summary.overallSentiment)}>
                    {getSentimentIcon(summary.overallSentiment)}
                    <span className="ml-1 capitalize">{t(`reviewSummary.sentiment.${summary.overallSentiment}`)}</span>
                  </Badge>
                  <span className={`text-2xl font-bold ${getSentimentColor(summary.overallSentiment)}`} data-testid="text-sentiment-score">
                    {summary.sentimentScore}%
                  </span>
                </div>
                <Progress value={summary.sentimentScore} className="h-3" />
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <TrendingUp className="h-5 w-5 text-green-500" />
                  {t("reviewSummary.trends.title")}
                </CardTitle>
                <CardDescription>{t("reviewSummary.trends.description")}</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {summary.trends.improving.length > 0 && (
                  <div>
                    <div className="flex items-center gap-1 text-sm text-green-600 dark:text-green-400 mb-1">
                      <TrendingUp className="h-3 w-3" />
                      {t("reviewSummary.trends.improving")}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {summary.trends.improving.map((item, i) => (
                        <Badge key={i} variant="outline" className="text-xs bg-green-50 dark:bg-green-950">
                          {item}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}
                {summary.trends.declining.length > 0 && (
                  <div>
                    <div className="flex items-center gap-1 text-sm text-red-600 dark:text-red-400 mb-1">
                      <TrendingDown className="h-3 w-3" />
                      {t("reviewSummary.trends.declining")}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {summary.trends.declining.map((item, i) => (
                        <Badge key={i} variant="outline" className="text-xs bg-red-50 dark:bg-red-950">
                          {item}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}
                {summary.trends.consistent.length > 0 && (
                  <div>
                    <div className="flex items-center gap-1 text-sm text-muted-foreground mb-1">
                      <Minus className="h-3 w-3" />
                      {t("reviewSummary.trends.consistent")}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {summary.trends.consistent.map((item, i) => (
                        <Badge key={i} variant="outline" className="text-xs">
                          {item}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}
                {summary.trends.improving.length === 0 && 
                 summary.trends.declining.length === 0 && 
                 summary.trends.consistent.length === 0 && (
                  <p className="text-sm text-muted-foreground">{t("reviewSummary.trends.noData")}</p>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Lightbulb className="h-5 w-5 text-amber-500" />
                  {t("reviewSummary.recommendations.title")}
                </CardTitle>
                <CardDescription>{t("reviewSummary.recommendations.description")}</CardDescription>
              </CardHeader>
              <CardContent>
                {summary.recommendations.length > 0 ? (
                  <ul className="space-y-2">
                    {summary.recommendations.map((rec, i) => (
                      <li key={i} className="flex gap-2 text-sm">
                        <span className="text-primary font-medium">{i + 1}.</span>
                        <span>{rec}</span>
                      </li>
                    ))}
                  </ul>
                ) : (
                  <p className="text-sm text-muted-foreground">{t("reviewSummary.recommendations.noData")}</p>
                )}
              </CardContent>
            </Card>
          </div>

          {summary.keyThemes.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle>{t("reviewSummary.keyThemes.title")}</CardTitle>
                <CardDescription>{t("reviewSummary.keyThemes.description")}</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                  {summary.keyThemes.map((theme, i) => (
                    <Card key={i} className="bg-muted/30">
                      <CardContent className="pt-4">
                        <div className="flex items-center justify-between mb-2">
                          <span className="font-medium">{theme.theme}</span>
                          <Badge className={getSentimentBadge(theme.sentiment)}>
                            {getSentimentIcon(theme.sentiment)}
                          </Badge>
                        </div>
                        <p className="text-sm text-muted-foreground mb-2">
                          {t("reviewSummary.keyThemes.mentionedIn")} {theme.count} {t("reviewSummary.reviews")}
                        </p>
                        {theme.examples.length > 0 && (
                          <div className="space-y-1">
                            {theme.examples.slice(0, 2).map((ex, j) => (
                              <p key={j} className="text-xs text-muted-foreground italic truncate">
                                "{ex}"
                              </p>
                            ))}
                          </div>
                        )}
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}
        </>
      )}
    </div>
  );
}

client/src/pages/blog-post.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { useParams, Link } from "wouter";
import { LandingHeader } from "@/components/landing-header";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowLeft, Calendar } from "lucide-react";
import { useLanguage } from "@/lib/i18n";
import { useEffect } from "react";
import { format } from "date-fns";
import { es, ca, enUS } from "date-fns/locale";
import type { Blog } from "@shared/schema";

const dateLocales = {
  es,
  ca,
  en: enUS,
};

function parseMarkdown(content: string): string {
  return content
    .replace(/^### (.*$)/gim, '<h3 class="text-xl font-semibold mt-6 mb-3">$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-semibold mt-8 mb-4">$1</h2>')
    .replace(/^# (.*$)/gim, '<h2 class="text-2xl font-semibold mt-8 mb-4">$1</h2>')
    .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
    .replace(/\*(.*)\*/gim, '<em>$1</em>')
    .replace(/^\* (.*$)/gim, '<li class="ml-4">$1</li>')
    .replace(/^\- (.*$)/gim, '<li class="ml-4">$1</li>')
    .replace(/\n\n/gim, '</p><p class="mt-4">')
    .replace(/\n/gim, '<br/>');
}

export default function BlogPostPage() {
  const { t, language } = useLanguage();
  const params = useParams();
  const slug = params.slug as string;

  const { data: blogData, isLoading, error } = useQuery<{ success: boolean; blog: Blog }>({
    queryKey: [`/api/blogs/${slug}`],
    enabled: !!slug,
  });

  const blog = blogData?.blog;

  useEffect(() => {
    if (blog) {
      document.title = blog.metaTitle || blog.title;

      let metaDesc = document.querySelector('meta[name="description"]');
      if (!metaDesc) {
        metaDesc = document.createElement('meta');
        metaDesc.setAttribute('name', 'description');
        document.head.appendChild(metaDesc);
      }
      metaDesc.setAttribute('content', blog.metaDescription || blog.subtitle || blog.content.substring(0, 160));

      let ogTitle = document.querySelector('meta[property="og:title"]');
      if (!ogTitle) {
        ogTitle = document.createElement('meta');
        ogTitle.setAttribute('property', 'og:title');
        document.head.appendChild(ogTitle);
      }
      ogTitle.setAttribute('content', blog.metaTitle || blog.title);

      let ogDesc = document.querySelector('meta[property="og:description"]');
      if (!ogDesc) {
        ogDesc = document.createElement('meta');
        ogDesc.setAttribute('property', 'og:description');
        document.head.appendChild(ogDesc);
      }
      ogDesc.setAttribute('content', blog.metaDescription || blog.subtitle || blog.content.substring(0, 160));
    }

    return () => {
      document.title = "HolaRevi";
    };
  }, [blog]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background">
        <LandingHeader />
        <main className="container mx-auto px-4 py-12">
          <div className="max-w-3xl mx-auto">
            <Skeleton className="h-8 w-48 mb-8" />
            <Skeleton className="h-12 w-full mb-4" />
            <Skeleton className="h-6 w-3/4 mb-8" />
            <Skeleton className="h-96 w-full" />
          </div>
        </main>
      </div>
    );
  }

  if (error || !blog) {
    return (
      <div className="min-h-screen bg-background">
        <LandingHeader />
        <main className="container mx-auto px-4 py-12">
          <div className="max-w-3xl mx-auto text-center py-16">
            <h1 className="text-2xl font-bold mb-4">{t("blog.notFound")}</h1>
            <p className="text-muted-foreground mb-8">{t("blog.notFoundDesc")}</p>
            <Button asChild>
              <Link href="/blog">
                <ArrowLeft className="mr-2 h-4 w-4" />
                {t("blog.backToList")}
              </Link>
            </Button>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <LandingHeader />

      <main className="container mx-auto px-4 py-12">
        <article className="max-w-3xl mx-auto">
          <Button variant="ghost" size="sm" asChild className="mb-8">
            <Link href="/blog">
              <ArrowLeft className="mr-2 h-4 w-4" />
              {t("blog.backToList")}
            </Link>
          </Button>

          <header className="mb-8">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-4">
              <Calendar className="h-4 w-4" />
              <time dateTime={new Date(blog.createdAt).toISOString()}>
                {format(new Date(blog.createdAt), "d MMMM yyyy", {
                  locale: dateLocales[language as keyof typeof dateLocales] || enUS,
                })}
              </time>
            </div>
            <h1 className="text-4xl font-bold tracking-tight mb-4">
              {blog.title}
            </h1>
            {blog.subtitle && (
              <p className="text-xl text-muted-foreground">
                {blog.subtitle}
              </p>
            )}
          </header>

          <div 
            className="prose prose-lg dark:prose-invert max-w-none"
            dangerouslySetInnerHTML={{ __html: `<p>${parseMarkdown(blog.content)}</p>` }}
          />
        </article>
      </main>

      <footer className="border-t py-8 mt-12">
        <div className="container mx-auto px-4 text-center text-sm text-muted-foreground">
          <p>&copy; {new Date().getFullYear()} HolaRevi. {t("landing.footer.allRightsReserved")}</p>
        </div>
      </footer>
    </div>
  );
}

client/src/pages/admin-blogs.tsx.content:
import { useEffect, useState } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import {
  LogOut,
  Loader2,
  Plus,
  Pencil,
  Trash2,
  FileText,
  Calendar,
  Eye,
  EyeOff,
  ExternalLink,
  Home,
} from "lucide-react";
import { Link } from "wouter";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";

interface Blog {
  id: string;
  title: string;
  subtitle: string | null;
  slug: string;
  content: string;
  metaTitle: string | null;
  metaDescription: string | null;
  published: boolean;
  createdAt: string;
  updatedAt: string;
}

interface BlogFormData {
  title: string;
  subtitle: string;
  slug: string;
  content: string;
  metaTitle: string;
  metaDescription: string;
  published: boolean;
}

const defaultFormData: BlogFormData = {
  title: "",
  subtitle: "",
  slug: "",
  content: "",
  metaTitle: "",
  metaDescription: "",
  published: false,
};

function generateSlug(title: string): string {
  return title
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .trim();
}

export default function AdminBlogs() {
  const { toast } = useToast();
  const [, setLocation] = useLocation();
  const [blogs, setBlogs] = useState<Blog[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState("");

  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingBlog, setEditingBlog] = useState<Blog | null>(null);
  const [formData, setFormData] = useState<BlogFormData>(defaultFormData);
  const [isSaving, setIsSaving] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  useEffect(() => {
    checkAuthAndFetchBlogs();
  }, []);

  const checkAuthAndFetchBlogs = async () => {
    try {
      const sessionResponse = await fetch("/api/admin/session", {
        credentials: "include",
      });
      const sessionData = await sessionResponse.json();

      if (!sessionData.authenticated) {
        setLocation("/admin/login");
        return;
      }

      const response = await fetch("/api/admin/blogs", {
        credentials: "include",
      });

      if (response.status === 401) {
        setLocation("/admin/login");
        return;
      }

      const data = await response.json();

      if (data.success) {
        setBlogs(data.blogs);
      } else {
        setError("Failed to load blogs");
      }
    } catch (err) {
      setError("An error occurred while loading blogs");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      await fetch("/api/admin/logout", {
        method: "POST",
        credentials: "include",
      });
      setLocation("/admin/login");
    } catch (err) {
      console.error("Logout failed:", err);
    }
  };

  const openCreateDialog = () => {
    setEditingBlog(null);
    setFormData(defaultFormData);
    setIsDialogOpen(true);
  };

  const openEditDialog = (blog: Blog) => {
    setEditingBlog(blog);
    setFormData({
      title: blog.title,
      subtitle: blog.subtitle || "",
      slug: blog.slug,
      content: blog.content,
      metaTitle: blog.metaTitle || "",
      metaDescription: blog.metaDescription || "",
      published: blog.published,
    });
    setIsDialogOpen(true);
  };

  const handleTitleChange = (title: string) => {
    setFormData(prev => ({
      ...prev,
      title,
      slug: !editingBlog ? generateSlug(title) : prev.slug,
      metaTitle: !prev.metaTitle ? title : prev.metaTitle,
    }));
  };

  const handleSave = async () => {
    if (!formData.title.trim()) {
      toast({
        title: "Error",
        description: "Title is required",
        variant: "destructive",
      });
      return;
    }

    if (!formData.slug.trim()) {
      toast({
        title: "Error",
        description: "Slug is required",
        variant: "destructive",
      });
      return;
    }

    if (!formData.content.trim()) {
      toast({
        title: "Error",
        description: "Content is required",
        variant: "destructive",
      });
      return;
    }

    setIsSaving(true);

    try {
      const url = editingBlog
        ? `/api/admin/blogs/${editingBlog.id}`
        : "/api/admin/blogs";
      const method = editingBlog ? "PATCH" : "POST";

      const response = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          title: formData.title.trim(),
          subtitle: formData.subtitle.trim() || null,
          slug: formData.slug.trim(),
          content: formData.content.trim(),
          metaTitle: formData.metaTitle.trim() || null,
          metaDescription: formData.metaDescription.trim() || null,
          published: formData.published,
        }),
      });

      const data = await response.json();

      if (data.success) {
        toast({
          title: "Success",
          description: editingBlog ? "Blog updated" : "Blog created",
        });
        setIsDialogOpen(false);
        checkAuthAndFetchBlogs();
      } else {
        toast({
          title: "Error",
          description: data.message || "Failed to save blog",
          variant: "destructive",
        });
      }
    } catch (err) {
      toast({
        title: "Error",
        description: "An error occurred while saving",
        variant: "destructive",
      });
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this blog post?")) {
      return;
    }

    setDeletingId(id);

    try {
      const response = await fetch(`/api/admin/blogs/${id}`, {
        method: "DELETE",
        credentials: "include",
      });

      const data = await response.json();

      if (data.success) {
        toast({
          title: "Success",
          description: "Blog deleted",
        });
        setBlogs(blogs.filter((b) => b.id !== id));
      } else {
        toast({
          title: "Error",
          description: data.message || "Failed to delete blog",
          variant: "destructive",
        });
      }
    } catch (err) {
      toast({
        title: "Error",
        description: "An error occurred while deleting",
        variant: "destructive",
      });
    } finally {
      setDeletingId(null);
    }
  };

  const handleTogglePublished = async (blog: Blog) => {
    try {
      const response = await fetch(`/api/admin/blogs/${blog.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ published: !blog.published }),
      });

      const data = await response.json();

      if (data.success) {
        toast({
          title: "Success",
          description: blog.published ? "Blog unpublished" : "Blog published",
        });
        checkAuthAndFetchBlogs();
      } else {
        toast({
          title: "Error",
          description: data.message || "Failed to update blog",
          variant: "destructive",
        });
      }
    } catch (err) {
      toast({
        title: "Error",
        description: "An error occurred",
        variant: "destructive",
      });
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b bg-card">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between gap-4 flex-wrap">
          <div className="flex items-center gap-3">
            <Link href="/admin">
              <Button variant="ghost" size="icon" data-testid="button-back">
                <Home className="h-5 w-5" />
              </Button>
            </Link>
            <div className="flex h-10 w-10 items-center justify-center rounded-md bg-primary/10">
              <FileText className="h-5 w-5 text-primary" />
            </div>
            <div>
              <h1 className="text-2xl font-bold" data-testid="text-title">
                Blog Management
              </h1>
              <p className="text-sm text-muted-foreground">
                Create and manage blog posts
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Button
              onClick={openCreateDialog}
              data-testid="button-create-blog"
            >
              <Plus className="h-4 w-4 mr-1" />
              New Blog
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleLogout}
              data-testid="button-logout"
            >
              <LogOut className="h-4 w-4 mr-1" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        {error && (
          <Card className="mb-6 border-destructive">
            <CardContent className="py-4">
              <p className="text-destructive">{error}</p>
            </CardContent>
          </Card>
        )}

        {blogs.length === 0 ? (
          <Card>
            <CardContent className="py-12 text-center">
              <FileText className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="text-lg font-medium mb-2">No blog posts yet</h3>
              <p className="text-muted-foreground mb-4">
                Create your first blog post to get started
              </p>
              <Button onClick={openCreateDialog}>
                <Plus className="h-4 w-4 mr-1" />
                Create Blog Post
              </Button>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-4">
            {blogs.map((blog) => (
              <Card key={blog.id} data-testid={`card-blog-${blog.id}`}>
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <CardTitle className="text-lg truncate">
                          {blog.title}
                        </CardTitle>
                        <Badge variant={blog.published ? "default" : "secondary"}>
                          {blog.published ? (
                            <>
                              <Eye className="h-3 w-3 mr-1" />
                              Published
                            </>
                          ) : (
                            <>
                              <EyeOff className="h-3 w-3 mr-1" />
                              Draft
                            </>
                          )}
                        </Badge>
                      </div>
                      {blog.subtitle && (
                        <CardDescription className="truncate">
                          {blog.subtitle}
                        </CardDescription>
                      )}
                    </div>
                    <div className="flex items-center gap-1">
                      {blog.published && (
                        <Button
                          variant="ghost"
                          size="icon"
                          asChild
                          data-testid={`button-preview-${blog.id}`}
                        >
                          <a href={`/blog/${blog.slug}`} target="_blank" rel="noopener noreferrer">
                            <ExternalLink className="h-4 w-4" />
                          </a>
                        </Button>
                      )}
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => openEditDialog(blog)}
                        data-testid={`button-edit-${blog.id}`}
                      >
                        <Pencil className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDelete(blog.id)}
                        disabled={deletingId === blog.id}
                        data-testid={`button-delete-${blog.id}`}
                      >
                        {deletingId === blog.id ? (
                          <Loader2 className="h-4 w-4 animate-spin" />
                        ) : (
                          <Trash2 className="h-4 w-4" />
                        )}
                      </Button>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="pt-0">
                  <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                    <span className="flex items-center gap-1">
                      <Calendar className="h-4 w-4" />
                      {format(new Date(blog.createdAt), "MMM d, yyyy")}
                    </span>
                    <span className="font-mono text-xs bg-muted px-2 py-1 rounded">
                      /blog/{blog.slug}
                    </span>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="ml-auto"
                      onClick={() => handleTogglePublished(blog)}
                    >
                      {blog.published ? "Unpublish" : "Publish"}
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </main>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {editingBlog ? "Edit Blog Post" : "Create Blog Post"}
            </DialogTitle>
            <DialogDescription>
              {editingBlog
                ? "Update the blog post details"
                : "Fill in the details for your new blog post"}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="title">Title *</Label>
              <Input
                id="title"
                value={formData.title}
                onChange={(e) => handleTitleChange(e.target.value)}
                placeholder="Enter blog title"
                data-testid="input-title"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="subtitle">Subtitle</Label>
              <Input
                id="subtitle"
                value={formData.subtitle}
                onChange={(e) =>
                  setFormData({ ...formData, subtitle: e.target.value })
                }
                placeholder="Enter subtitle (optional)"
                data-testid="input-subtitle"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="slug">URL Slug *</Label>
              <div className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">/blog/</span>
                <Input
                  id="slug"
                  value={formData.slug}
                  onChange={(e) =>
                    setFormData({ ...formData, slug: generateSlug(e.target.value) })
                  }
                  placeholder="url-slug"
                  className="font-mono"
                  data-testid="input-slug"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="content">Content * (Markdown supported)</Label>
              <Textarea
                id="content"
                value={formData.content}
                onChange={(e) =>
                  setFormData({ ...formData, content: e.target.value })
                }
                placeholder="Write your blog content here..."
                className="min-h-[200px] font-mono text-sm"
                data-testid="input-content"
              />
            </div>

            <div className="border-t pt-4">
              <h4 className="font-medium mb-3">SEO Settings</h4>
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="metaTitle">Meta Title</Label>
                  <Input
                    id="metaTitle"
                    value={formData.metaTitle}
                    onChange={(e) =>
                      setFormData({ ...formData, metaTitle: e.target.value })
                    }
                    placeholder="SEO title (defaults to blog title)"
                    data-testid="input-meta-title"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="metaDescription">Meta Description</Label>
                  <Textarea
                    id="metaDescription"
                    value={formData.metaDescription}
                    onChange={(e) =>
                      setFormData({ ...formData, metaDescription: e.target.value })
                    }
                    placeholder="SEO description for search engines"
                    className="min-h-[80px]"
                    data-testid="input-meta-description"
                  />
                </div>
              </div>
            </div>

            <div className="flex items-center justify-between border-t pt-4">
              <div className="space-y-0.5">
                <Label htmlFor="published">Published</Label>
                <p className="text-sm text-muted-foreground">
                  Make this post visible to the public
                </p>
              </div>
              <Switch
                id="published"
                checked={formData.published}
                onCheckedChange={(checked) =>
                  setFormData({ ...formData, published: checked })
                }
                data-testid="switch-published"
              />
            </div>
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setIsDialogOpen(false)}
              disabled={isSaving}
            >
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              disabled={isSaving}
              data-testid="button-save"
            >
              {isSaving ? (
                <>
                  <Loader2 className="h-4 w-4 mr-1 animate-spin" />
                  Saving...
                </>
              ) : editingBlog ? (
                "Update"
              ) : (
                "Create"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

